    imageFallback: "https://source.unsplash.com/800x450/?middle-east-conflict",
    imageQuery: "middle east conflict peace",
    imageCaption: "El conflicto entre Israel y Hamas dejó destrucción masiva en la Franja de Gaza.",
    hasGallery: false,
